const ECONOMICS_PERIOD_OPTIONS = new Set(['day', 'week', 'month', 'quarter', 'half-year', 'year', 'all']);

function readStoredEconomicsPeriod() {
  if (typeof window === 'undefined') return 'month';
  try {
    const raw = String(window.localStorage.getItem(ECONOMICS_PERIOD_STORAGE_KEY) || '').trim().toLowerCase();
    return ECONOMICS_PERIOD_OPTIONS.has(raw) ? raw : 'month';
  } catch (_error) {
    return 'month';
  }
}

function readStoredEconomicsProvider() {
  if (typeof window === 'undefined') return 'all';
  try {
    const raw = String(window.localStorage.getItem(ECONOMICS_PROVIDER_STORAGE_KEY) || '').trim().toLowerCase();
    return raw || 'all';
  } catch (_error) {
    return 'all';
  }
}

function writeStoredValue(key, value) {
  if (typeof window === 'undefined') return;
  try {
    window.localStorage.setItem(key, String(value || ''));
  } catch (_error) {
    // ignore storage failures
  }
}

function formatEconomicsProviderLabel(provider) {
  const value = String(provider || '').trim().toLowerCase();
  const labels = {
    all: 'All Providers',
    openai: 'OpenAI',
    google_tts: 'Google TTS',
    google_translate: 'Google Translate',
    deepl_free: 'DeepL',
    azure_translator: 'Azure Translator',
    livekit: 'LiveKit',
    cloudflare_r2_class_a: 'Cloudflare R2 Class A',
    cloudflare_r2_class_b: 'Cloudflare R2 Class B',
    cloudflare_r2_storage: 'Cloudflare R2 Storage',
    youtube_api: 'YouTube API',
    youtube_proxy: 'YouTube Proxy',
    perplexity: 'Perplexity',
    stripe: 'Stripe',
    agent_tts: 'Agent TTS',
    offline_tts: 'Offline TTS',
    app_internal: 'App Internal',
    libretranslate: 'LibreTranslate',
    mymemory: 'MyMemory',
    argos_offline: 'Argos Offline',
  };
  if (labels[value]) return labels[value];
  if (!value) return 'Unassigned';
  return value
    .split('_')
    .filter(Boolean)
    .map((part) => part.charAt(0).toUpperCase() + part.slice(1))
    .join(' ');
}

function formatEconomicsUnitsLabel(unitsType, uiLang) {
  const value = String(unitsType || '').trim().toLowerCase();
  const map = {
    tokens_in: uiLang === 'de' ? 'Input-Tokens' : 'tokens in',
    tokens_out: uiLang === 'de' ? 'Output-Tokens' : 'tokens out',
    chars: uiLang === 'de' ? 'Zeichen' : 'chars',
    requests: uiLang === 'de' ? 'Anfragen' : 'requests',
    audio_minutes: uiLang === 'de' ? 'Audiominuten' : 'audio min',
    youtube_quota_units: uiLang === 'de' ? 'YouTube-Quota' : 'yt quota',
    operations: uiLang === 'de' ? 'Operationen' : 'ops',
    mb_month: uiLang === 'de' ? 'MB/Monat' : 'MB/month',
  };
  return map[value] || value || 'units';
}

function formatEconomicsCompactNumber(value) {
  const numeric = Number(value || 0);
  if (!Number.isFinite(numeric)) return '0';
  if (Math.abs(numeric) >= 100) return numeric.toFixed(0);
  if (Math.abs(numeric) >= 10) return numeric.toFixed(1);
  if (Math.abs(numeric) >= 1) return numeric.toFixed(2);
  return numeric.toFixed(3);
}

function formatBillingPriceLabel(plan, uiLang, fallbackLabel = '') {
  const amountValue = Number(plan?.amount_value);
  const currency = String(plan?.currency || '').trim().toUpperCase();
  const interval = String(plan?.recurring_interval || '').trim().toLowerCase();
  const intervalCount = Number(plan?.recurring_interval_count || 1);
  if (!Number.isFinite(amountValue) || amountValue < 0 || !currency) {
    return String(fallbackLabel || '').trim();
  }
  const amountText = `${amountValue.toFixed(2)} ${currency}`;
  if (!interval) {
    return amountText;
  }
  const intervalLabels = uiLang === 'de'
    ? { day: 'Tag', week: 'Woche', month: 'Monat', year: 'Jahr' }
    : { day: 'день', week: 'неделя', month: 'месяц', year: 'год' };
  const intervalLabel = intervalLabels[interval] || interval;
  if (intervalCount > 1) {
    return uiLang === 'de'
      ? `${amountText} / ${intervalCount} ${intervalLabel}`
      : `${amountText} / ${intervalCount} ${intervalLabel}`;
  }
  return `${amountText} / ${intervalLabel}`;
}

function formatDateInputValue(value) {
  const date = value instanceof Date ? new Date(value) : new Date(value || Date.now());
  if (Number.isNaN(date.getTime())) {
    return '';
  }
  const yyyy = String(date.getFullYear());
  const mm = String(date.getMonth() + 1).padStart(2, '0');
  const dd = String(date.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

function addCalendarDays(value, days) {
  const date = new Date(value || Date.now());
  if (Number.isNaN(date.getTime())) {
    return formatDateInputValue(new Date());
  }
  date.setDate(date.getDate() + Number(days || 0));
  return formatDateInputValue(date);
}

function buildDefaultAnalyticsCalendarRange() {
  const today = formatDateInputValue(new Date());
  return {
    startDate: addCalendarDays(today, -29),
    endDate: today,
  };
}

function beginAsyncGuard(ref) {
  const nextToken = Number(ref?.current || 0) + 1;
  ref.current = nextToken;
  return nextToken;
}

function invalidateAsyncGuard(ref) {
  return beginAsyncGuard(ref);
}

function invalidateAsyncGuards(...refs) {
  refs.forEach((ref) => {
    invalidateAsyncGuard(ref);
  });
}

function isAsyncGuardCurrent(ref, token) {
  return Number(ref?.current || 0) === Number(token || 0);
}

function parseIsoDateParts(value) {
  const raw = String(value || '').trim();
  const match = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) {
    return null;
  }
  return {
    year: Number(match[1]),
    month: Number(match[2]),
    day: Number(match[3]),
  };
}

function formatAnalyticsCalendarDisplayDate(value, locale = 'ru-RU') {
  const parts = parseIsoDateParts(value);
  if (!parts) {
    return '';
  }
  const safeDate = new Date(parts.year, parts.month - 1, parts.day);
  if (Number.isNaN(safeDate.getTime())) {
    return '';
  }
  return new Intl.DateTimeFormat(locale, {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
  }).format(safeDate);
}

const HOME_SNAPSHOT_AUTO_REFRESH_MAX_AGE_MS = 30 * 60 * 1000;

function parseIsoTimestampMs(value) {
  const raw = String(value || '').trim();
  if (!raw) {
    return null;
  }
  const parsed = Date.parse(raw);
  return Number.isFinite(parsed) ? parsed : null;
}

function isSnapshotRefreshDue(value, maxAgeMs = HOME_SNAPSHOT_AUTO_REFRESH_MAX_AGE_MS) {
  const timestampMs = parseIsoTimestampMs(value);
  if (!Number.isFinite(timestampMs)) {
    return true;
  }
  return (Date.now() - timestampMs) >= maxAgeMs;
}

function formatSnapshotDateTime(value, locale = 'ru-RU') {
  const timestampMs = parseIsoTimestampMs(value);
  if (!Number.isFinite(timestampMs)) {
    return '';
  }
  return new Intl.DateTimeFormat(locale, {
    day: '2-digit',
    month: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
  }).format(new Date(timestampMs));
}

